-- Table structure for table `tool_call`
--

DROP TABLE IF EXISTS `tool_call`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `tool_call` (
  `id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '主键ID',
  `tool_call_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工具调用唯一标识',
  `run_id` varchar(36) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '所属Agent运行ID',
  `tool_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '工具名称',
